import React from "react";
import Row from "./Row";

function Home() {
  return (
    <>
      <Row title="NETFLIX ORIGINAL" />
      <Row title="TRENDING NOW" />
      <Row title="TOP RATED" />
      <Row title="ACTIONS MOVIES" />
      <Row title="COMEDY MOVIES" />
    </>
  );
}

export default Home;
